FileUtil = {}
FileUtil.MapPath = ""
FileUtil.RootPath = ""

function FileUtil:setMapPath(path)
    self.MapPath = tostring(path) .. "/"
end

function FileUtil:setRootPath(path)
    self.RootPath = tostring(path) .. "/"
end

function FileUtil:getMapPath()
    return self.MapPath
end

function FileUtil:getRootPath()
    return self.RootPath
end

function FileUtil:getScriptPath()
    local result = "./" .. tostring(ScriptSetting.getScriptPath()) .. "/main"
    result = string.gsub(result, "\\", "\\\\")
    result = string.gsub(result, "/", "\\\\")
    LogUtil.log("FileUtil:getScriptPath " .. result)
    return result
end

function FileUtil:getSettingPath()
    local path = self.RootPath .. ScriptSetting.getScriptPath()
    path = string.gsub(path, "ClientGame", "GameSetting") .. "/"
    return path
end

function FileUtil.getGameConfigFromYml(name)
    local path = FileUtil:getSettingPath() .. name
    if not string.find(name, ".yml") then
        path = path .. ".yml"
    end
    local file = io.open(path, "r")
    if not file then
        return
    end
    local content = file.read(file, "*a")
    io.close(file)
    return TinyParse(content)
end

function FileUtil.getGameConfigFromCsv(name, row)
    local path = FileUtil:getSettingPath() .. name
    local file = io.open(path, "r")
    if not file then
        return
    end
    row = row or 2
    return CsvUtil.loadCsvFile(path, row)
end

function FileUtil.getConfigFromYml(name, checkExist)
    local path = FileUtil:getMapPath() .. name
    if not string.find(name, ".yml") then
        path = path .. ".yml"
    end
    local file = io.open(path, "r")
    if not file then
        if checkExist then
            return {}
        end
        LogUtil.log("FileUtil.getConfigFromYml not file " .. path, LogUtil.LogLevel.Error)
    end
    local content = file.read(file, "*a")
    io.close(file)
    return TinyParse(content)
end

function FileUtil.getConfigFromCsv(name, row, checkExist)
    local path = FileUtil:getMapPath() .. name
    if checkExist then
        local file = io.open(path, "r")
        if not file then
            return {}
        end
    end
    row = row or 2
    return CsvUtil.loadCsvFile(path, row)
end

function FileUtil.getConfigFromXml(name)
    local path = FileUtil:getMapPath() .. name
    local file = io.open(path)
    if not file then
        LogUtil.log(string.format("FileUtil.getConfigFromXml %s failed", name), LogUtil.LogLevel.Error)
        return nil
    end

    local myxml = file:read('*all')

    -- Specify as many/few of these as you like
    local result = {}
