        startElement = function(name, nsURI, nsPrefix)
            --print(name,nsURI,nsPrefix)

            key = name
            result[key] = {}
        end, -- When "<foo" or <x:foo is seen
        attribute = function(name, value, nsURI, nsPrefix)
            --print(name,value,nsURI,nsPrefix)

            table.insert(result[key],
                    {
                        name = name,
                        value = value,
                    })
        end, -- attribute found on current element
        closeElement = function(name, nsURI)
            --print(name,nsURI)

            --TODO
        end, -- When "</foo>" or </x:foo> or "/>" is seen
        --text         = function(text,cdata)
        --    print(text,cdata)
        --end, -- text and CDATA nodes (cdata is true for cdata nodes)
        --comment      = function(content)
        --    print(content)
        --end, -- comments
        --pi           = function(target,content)
        --    print(target,content)
        --end, -- processing instructions e.g. "<?yes mon?>"
    }

    -- Ignore whitespace-only text nodes and strip leading/trailing whitespace from text
    -- (does not strip leading/trailing whitespace from CDATA)
    parser:parse(myxml, { stripWhitespace = true })

    return result
end

function FileUtil.getConfigFromJson(path)
    local file = io.open(path, "r")
    if not file then
        LogUtil.log(string.format("FileUtil.getConfigFromJson %s not exist", path), LogUtil.LogLevel.Info)
        return nil
    end
    local content = file.read(file, "*a")
    io.close(file)
    return json.decode(content)
end

return FileUtil